import { hasPermissionCode } from '../utils/erpPermissionCode';

const APP = 'erp-mes';

function mesResource(resource: string) {
  const base = `${APP}:${resource}`;
  const canRead = hasPermissionCode(`${base}:read`);
  const canWrite = hasPermissionCode(`${base}:write`);
  return {
    canRead,
    canWrite,
    canCreate: canWrite,
    canUpdate: canWrite,
    canDelete: hasPermissionCode(`${base}:delete`) || canWrite,
  };
}

/** Danh mục BOM — `/sx/bom` */
export function useMesBomPermissions() {
  return mesResource('production:boms');
}

/** Công đoạn — `/sx/cong-doan` */
export function useMesCongDoanPermissions() {
  return mesResource('production:stages');
}

/** Định mức khoán — `/sx/dinh-muc-khoan` */
export function useMesDinhMucKhoanPermissions() {
  return mesResource('production:norms');
}

/** Lệnh sản xuất — `/sx/lsx` */
export function useMesLsxPermissions() {
  const base = `${APP}:production:orders`;
  const canWrite = hasPermissionCode(`${base}:write`);
  return {
    canRead: hasPermissionCode(`${base}:read`),
    canWrite,
    canCreate: canWrite,
    canUpdate: canWrite,
    canRelease: hasPermissionCode(`${base}:release`) || canWrite,
    canComplete: hasPermissionCode(`${base}:complete`) || canWrite,
    canClose: hasPermissionCode(`${base}:close`) || canWrite,
  };
}

/** Sản phẩm hoàn thành (QC) — `/sx/san-pham-hoan-thanh` */
export function useMesCompletionQcPermissions() {
  const base = `${APP}:production:completions`;
  const canRead = hasPermissionCode(`${base}:read`);
  const canWrite = hasPermissionCode(`${base}:write`);
  return {
    canRead,
    canWrite,
    canApprove: hasPermissionCode(`${base}:approve`) || canWrite,
    canReject: hasPermissionCode(`${base}:reject`) || canWrite,
  };
}

/** Báo cáo năng suất — `/sx/nang-suat` */
export function useMesNangSuatReportPermissions() {
  const base = `${APP}:production-reports:productivity`;
  return {
    canRead: hasPermissionCode(`${base}:read`),
    canExport: hasPermissionCode(`${base}:export`) || hasPermissionCode(`${base}:read`),
  };
}

/** BC thành phẩm đơn hàng — `/sx/bao-cao-don-hang` */
export function useMesOrderFinishedReportPermissions() {
  const base = `${APP}:production-reports:order-finished-goods`;
  return {
    canRead: hasPermissionCode(`${base}:read`),
    canExport: hasPermissionCode(`${base}:export`) || hasPermissionCode(`${base}:read`),
    canPrint: hasPermissionCode(`${base}:read`),
    canConfig: hasPermissionCode(`${base}:read`),
  };
}
